# -*- coding: utf-8 -*-
AI_HPC = [
    {"hero":True,"sub":"AI/HPC Stocks & Infrastructure","h3":"Meta commits hundreds of billions to multi-gigawatt superintelligence clusters","summary":"Mark Zuckerberg formalized Meta Compute and confirmed plans to pour hundreds of billions of dollars into several multi-gigawatt data center campuses chasing superintelligence.","body":["Meta said it will fund a string of multi-gigawatt computing clusters as it races rivals to build superintelligence, lifting its 2026 capital spending guidance into the range of 125 to 145 billion dollars. The company's footprint already spans more than 26 US campuses and four international sites totaling over 50 million square feet.","Zuckerberg has spent aggressively on talent and acquisitions for the new effort, taking a 49 percent stake in Scale AI and recruiting its CEO Alexandr Wang along with Nat Friedman and Daniel Gross. The buildout cements Meta as one of the largest AI infrastructure spenders alongside Microsoft, Google and Amazon."],"sources":[("Data Center Dynamics","https://www.datacenterdynamics.com/en/news/meta-establishes-meta-compute-plans-multiple-gigawatt-plus-scale-ai-data-centers/"),("Fortune","https://fortune.com/2026/02/04/meta-hyperion-ai-data-center-louisiana-expansion/")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"Chevron signs 20-year power deal for Microsoft's giant West Texas AI campus","summary":"Chevron agreed to supply electricity for two decades to a 2.7-gigawatt Microsoft data center planned in the Permian Basin.","body":["Chevron struck a 20-year agreement to sell power to Microsoft for what could become one of the largest AI data centers in the US, a 2.7-gigawatt campus on more than 2,000 acres in Reeves County, Texas. The deal taps oil and gas country to feed surging compute demand.","The agreement lands as US data center power needs are projected to hit 41 gigawatts in 2026 and 66 gigawatts in 2027. Texas overtook Northern Virginia as the world's top primary data center market in May 2026."],"sources":[("Yahoo Finance","https://finance.yahoo.com/energy/articles/chevron-strikes-power-deal-microsoft-120000499.html")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"Tesla and Sunrun pool 16 GW of home batteries to sell to data centers","summary":"Sunrun, Tesla and Renew Home agreed to aggregate residential batteries and thermostats into a virtual power plant sold directly to hyperscalers.","body":["The three companies said on June 24 they will combine more than 16 gigawatts of home batteries and smart thermostats into what they call the largest distributed power plant in the country, with capacity sold to hyperscale data center operators rather than only utilities. Analysts caution that only about 4 gigawatts is firm battery capacity, with 300 megawatts deployable now in Virginia.","The arrangement signals a new front in the scramble to power AI, with rooftop storage pitched as a flexible supply source for grid-strained regions hosting heavy compute."],"sources":[("Tech Times","https://www.techtimes.com/articles/319141/20260626/tesla-sunrun-lock-16-gw-home-batteries-ai-data-center-grid-deal.htm")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"Backblaze lands $335M multi-exabyte storage deal with CoreWeave","summary":"CoreWeave will use Backblaze for cost-efficient capacity supporting its managed storage, a deal worth up to 335 million dollars.","body":["Backblaze announced on June 23 a multi-exabyte storage agreement with CoreWeave valued at as much as 335 million dollars, providing capacity that underpins CoreWeave's managed storage infrastructure for AI workloads. The pact deepens the neocloud's supply chain as it scales.","CoreWeave and rival Nebius both entered the Nasdaq-100 effective June 22, triggering index-fund buying. CoreWeave's backlog has swelled on multibillion-dollar commitments including an expanded roughly 21 billion dollar agreement with Meta."],"sources":[("SEC EDGAR","https://www.sec.gov/Archives/edgar/data/0001462056/000162828026044804/ex991backblazecoreweavepre.htm"),("Crowdfund Insider","https://www.crowdfundinsider.com/2026/06/285326-ai-infrastructure-enablers-coreweave-and-nebius-see-shares-surge-on-nasdaq-100-inclusion-update/")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"OpenAI's Broadcom-built Jalapeno chip targets 50% cheaper inference","summary":"OpenAI detailed Jalapeno, a custom accelerator co-developed with Broadcom in nine months and aimed at slashing inference costs.","body":["OpenAI's Jalapeno accelerator, built with Broadcom, is designed for initial deployment by the end of 2026 and pitched at roughly 50 percent cheaper inference. The fast nine-month development reflects how aggressively labs are racing to own silicon and cut their dependence on Nvidia.","The push mirrors broader vertical integration across the industry, where hyperscalers and labs increasingly design their own chips to control cost and supply for ballooning AI demand."],"sources":[("BuildFastWithAI","https://www.buildfastwithai.com/blogs/ai-news-today-june-26-2026"),("OpenAI","https://openai.com/news/product-releases/")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"TSMC stock outpaces Nvidia as AI foundry demand stays hot","summary":"Taiwan Semiconductor's shares jumped 33 percent in 2026, beating Nvidia, as advanced node capacity captured a record share of wafer revenue.","body":["TSMC continues to ride the AI boom, with consensus pointing to about 34 percent earnings growth in 2026 and advanced nodes making up 74 percent of wafer revenue at operating margins above 58 percent. Its stock has climbed 33 percent this year, outpacing Nvidia.","Nvidia and TSMC remain locked together in the AI value chain, with Nvidia controlling chip design and software economics as hyperscalers deploy Blackwell and prepare for Rubin instances built on TSMC silicon."],"sources":[("24/7 Wall St.","https://247wallst.com/investing/2026/04/29/nvidia-vs-tsm-earnings-reveal-ai-hardware-power-split/"),("Digitimes","https://www.digitimes.com/news/a20260302PD213/nvidia-tsmc-infrastructure-earnings-revenue.html")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"Nvidia pushes into Windows PCs with RTX Spark and Vera superchip","summary":"At Computex, Nvidia unveiled an Arm-based RTX Spark superchip and a Vera CPU, challenging Intel and AMD in AI laptops.","body":["Nvidia introduced the RTX Spark superchip, built with MediaTek to run Windows on Arm and slated to debut in Dell and Lenovo machines this fall. The move stakes Nvidia's claim across the entire AI stack, from data center to consumer PC.","The company also showed its new Vera CPU and put Spectrum-X Ethernet Photonics into full production for its Vera Rubin AI factory platform, signaling a coordinated push from chips to networking."],"sources":[("CNBC","https://www.cnbc.com/2026/06/02/nvidias-new-pc-chips-are-ceos-bid-to-own-every-part-of-ai-stack.html"),("Bloomberg","https://www.bloomberg.com/news/articles/2026-06-01/nvidia-enters-windows-laptop-market-taking-on-intel-and-amd")]},
    {"sub":"Foundation Models & Releases","h3":"OpenAI unveils GPT-5.6 Sol, Terra and Luna but limits the rollout","summary":"OpenAI announced three new flagship models on June 26 and said it would restrict access to trusted partners at the government's request.","body":["OpenAI's next generation GPT-5.6 lineup includes Sol as the flagship, Terra for balanced everyday use and Luna as a faster low-cost option. The company said it is complying with a White House request to limit the initial rollout to a small group of trusted partners, the first time the US has preemptively asked an American lab to stagger a launch.","OpenAI pushed back on the precedent, saying such government access processes should not become the long-term default because they keep the best tools from developers, enterprises and cyber defenders. It plans wider availability in the coming weeks."],"sources":[("CNBC","https://www.cnbc.com/amp/2026/06/26/openai-limits-new-ai-models-to-trusted-partners-request-us-government.html"),("TechCrunch","https://techcrunch.com/2026/06/26/openai-limits-gpt-5-6-rollout-after-government-request-says-restrictions-shouldnt-be-the-norm/")]},
    {"sub":"Foundation Models & Releases","h3":"Anthropic's Claude Fable 5 launches then goes dark on export order","summary":"Anthropic's Mythos-class Fable 5 set new benchmark highs on June 9, but a US export directive forced it offline days later.","body":["Claude Fable 5 debuted as Anthropic's most capable widely released model, topping nearly all tested benchmarks with always-on adaptive thinking, a one-million-token context window and 128K output tokens. It priced at 10 and 50 dollars per million tokens, double Opus 4.8.","On June 12 a Commerce Department export-control directive ordered Anthropic to suspend access to Fable 5 and Mythos 5 for any foreign national worldwide. Because nationality cannot be gated in real time, both models went offline for all users, with US access expected back around July 1."],"sources":[("Releasebot","https://releasebot.io/updates/anthropic/claude"),("Developers Digest","https://www.developersdigest.tech/blog/codex-vs-claude-code-june-2026")]},
    {"sub":"Foundation Models & Releases","h3":"Microsoft launches seven in-house MAI models to ease OpenAI reliance","summary":"Microsoft AI debuted a family of seven models spanning reasoning, coding, image and voice to cut costs and capture more margin.","body":["The MAI family, unveiled by Microsoft AI chief Mustafa Suleyman, includes MAI-Thinking-1 for reasoning, MAI-Code-1-Flash for agentic coding, image, transcription and voice models, all trained in-house. Microsoft says MAI-Thinking-1 scores 97 percent on AIME 2025 and matches Claude Opus 4.6 on SWE-Bench Pro.","Satya Nadella framed the move as a shift from consuming a frontier model to participating at the frontier. Microsoft has invested heavily in both OpenAI and Anthropic but is now building efficient models to capture margin and lower developer costs."],"sources":[("CNBC","https://www.cnbc.com/2026/06/02/microsoft-unveils-new-ai-models-lessen-reliance-on-openai-lower-costs.html"),("Windows Central","https://www.windowscentral.com/software-apps/microsoft-launches-seven-in-house-ai-models-to-cut-developer-costs-and-reduce-reliance-on-openai")]},
    {"sub":"Foundation Models & Releases","h3":"xAI ships Grok 4.3 on Bedrock and a long-running agent mode","summary":"xAI brought Grok 4.3 to Amazon Bedrock with a million-token context and added an autonomous goal mode to Grok Build.","body":["Grok 4.3 reached general availability on Amazon Bedrock with a one-million-token context window, configurable reasoning levels and low-hallucination performance pitched for enterprise agents and long-document work. xAI also made Grok models natively available on Databricks Agent Bricks.","The company introduced a long-running autonomous mode in Grok Build that plans, executes and verifies larger tasks, and released Grok Imagine Video 1.5 generally across its API, web and mobile apps."],"sources":[("Releasebot","https://releasebot.io/updates/xai"),("Basenor","https://www.basenor.com/blogs/news/xai-grok-lands-on-databricks-at-the-2026-data-ai-summit")]},
    {"sub":"Foundation Models & Releases","h3":"Mistral updates OCR 4 and enterprise connectors for self-hosting","summary":"Mistral released OCR 4 with bounding boxes and confidence scores across 170 languages plus tighter enterprise integration controls.","body":["Mistral's OCR 4 adds block classification, inline confidence scores and bounding boxes, supports 170 languages and runs in a single container for fully self-hosted deployments. The French lab continues to lean into on-premise and sovereign use cases.","Mistral also expanded its Connectors with richer admin controls, scoped API keys and multi-account support, sharpening its pitch to enterprises wary of sending data to closed US clouds."],"sources":[("Mistral AI","https://mistral.ai/news/"),("Releasebot","https://releasebot.io/updates/mistral")]},
    {"sub":"Foundation Models & Releases","h3":"Nobel laureate John Jumper leaves DeepMind for Anthropic","summary":"AlphaFold creator John Jumper is departing Google DeepMind after nearly nine years to join Anthropic, deepening a talent exodus.","body":["Jumper, who shared the 2024 Nobel Prize in Chemistry for AlphaFold2, announced he is leaving DeepMind to join the Claude maker, saying he would recharge before starting. His move aligns with Anthropic's expanding push into life sciences and computational biology.","The departure landed a day after Gemini co-lead Noam Shazeer left for OpenAI, marking two landmark losses for Google within 48 hours as the talent war among frontier labs intensifies."],"sources":[("TechCrunch","https://techcrunch.com/2026/06/20/nobel-laureate-john-jumper-is-leaving-deepmind-for-rival-anthropic/"),("CNBC","https://www.cnbc.com/2026/06/19/john-jumper-to-leave-google-deepmind-for-anthropic.html")]},
    {"sub":"Chinese AI Ecosystem","h3":"China drafts $295B plan for a national AI grid that locks out Nvidia","summary":"Beijing is preparing a five-year program to link data centers into one computing grid, requiring 80 percent domestic technology.","body":["China is drafting a 295 billion dollar plan to connect thousands of data centers into a unified national computing grid, mandating that at least 80 percent of underlying technology come from domestic suppliers. The rule would effectively exclude Nvidia and AMD from a vast procurement pool.","The push reflects Beijing's drive for compute self-sufficiency amid US export controls, channeling demand toward homegrown accelerators and infrastructure."],"sources":[("Tech Times","https://www.techtimes.com/articles/318868/20260622/china-ai-data-center-grid-locks-out-nvidia-295-billion-domestic-chip-mandate.htm")]},
    {"sub":"Chinese AI Ecosystem","h3":"Huawei ramps Ascend output and touts 950PR inference chip","summary":"Huawei plans to roughly double Ascend chip production in 2026 and launched the 950PR, claiming a big lead over Nvidia's H20 on FP4.","body":["Huawei is preparing to ship around 600,000 flagship Ascend 910C chips in 2026, about double the prior year, and lift total Ascend output toward 1.6 million dies. The new Ascend 950PR delivers 1.56 petaflops and claims 2.8 times the FP4 performance of Nvidia's H20, with ByteDance committing billions in orders.","Built on an enhanced 7nm SMIC process with a CUDA-compatible software stack to ease migration, the lineup anchors China's effort to build a fully domestic chip ecosystem, though efficiency still trails TSMC-made rivals."],"sources":[("Tom's Hardware","https://www.tomshardware.com/tech-industry/semiconductors/huaweis-ascend-ai-chip-ecosystem-scales"),("Yahoo Finance","https://finance.yahoo.com/news/huaweis-bold-ai-chip-push-180552201.html")]},
    {"sub":"Chinese AI Ecosystem","h3":"Anthropic tells Senate Alibaba ran largest known distillation attack","summary":"Anthropic accused Alibaba-linked operators of running 28.8 million unauthorized Claude exchanges to extract capabilities illicitly.","body":["In a letter to senators, Anthropic said operators tied to Alibaba's Qwen lab ran nearly 28.8 million unauthorized exchanges with Claude over six weeks using about 25,000 fraudulent accounts and proxies to bypass geographic restrictions on Chinese entities. It called the campaign the largest known distillation attack against the company.","The accusation, which Alibaba disputes, fed Anthropic's push for stronger export controls and screening of high-volume API usage. Anthropic said it earlier detected smaller efforts linked to DeepSeek, Moonshot AI and MiniMax."],"sources":[("CNBC","https://www.cnbc.com/2026/06/24/anthropic-alibaba-distillation-campaign.html"),("Tech Times","https://www.techtimes.com/articles/319105/20260625/alibaba-ran-largest-known-ai-theft-campaign-against-claude-anthropic-tells-senate.htm")]},
    {"sub":"Chinese AI Ecosystem","h3":"Chinese labs hold four of top five open-weight model slots","summary":"GLM-5, Qwen3.5, Kimi K2.5 and DeepSeek V4 dominate open-weight leaderboards as Chinese models close the gap with the West.","body":["Zhipu AI's GLM-5 leads BenchLM's open-weight ranking, with Chinese labs holding four of the top five positions and each excelling in different dimensions, from Qwen's multilingual strength to DeepSeek's coding and Kimi's agent frameworks. DeepSeek remains the cheapest frontier option at roughly 14 to 30 cents per million input tokens.","The clustering underscores how aggressively Chinese open-weight models have caught up to Western frontier systems in 2026, raising the stakes in debates over export controls and distillation."],"sources":[("Stanford HAI","https://hai.stanford.edu/policy/beyond-deepseek-chinas-diverse-open-weight-ai-ecosystem-and-its-policy-implications"),("RadarAI","https://radarai.top/en/articles/china-ai-models-to-watch-in-2026-deepseek-qwen-kimi-and-more")]},
    {"sub":"Agents & Automation","h3":"OpenAI escalates coding-agent war with free Codex and migration tools","summary":"OpenAI is offering enterprises two months of free Codex and one-click migration to pull them off Anthropic's Claude Code.","body":["The fight for AI-assisted coding has turned into open commercial warfare, with OpenAI dangling two months of free Codex usage and one-click migration to lure teams away from Claude Code. OpenAI made GPT-5.5 the Codex default and shipped automations, computer use and a headless SDK.","Benchmarks are nearly tied, with Codex plus GPT-5.5 leading Terminal-Bench at 83.4 percent and Claude Code plus Fable 5 at 83.1 percent. The Anthropic export shutdown briefly handed OpenAI an opening as Claude went offline."],"sources":[("Tech Times","https://www.techtimes.com/articles/318184/20260610/openai-vs-anthropic-coding-war-free-codex-one-click-migration-attack-claudes-lock.htm"),("Developers Digest","https://www.developersdigest.tech/blog/codex-vs-claude-code-june-2026")]},
    {"sub":"Agents & Automation","h3":"Codex Remote reaches general availability for phone-driven coding","summary":"OpenAI's Codex Remote is now generally available, letting users run and approve coding work on a connected Mac or Windows host from the ChatGPT app.","body":["Codex Remote lets developers start or continue tasks on a connected desktop directly from the ChatGPT mobile app and approve actions from their phone, pushing agentic coding into untethered, asynchronous workflows. The release follows OpenAI's broader Codex buildout including computer use and an SDK.","The launch reflects how coding agents are moving from in-editor copilots to autonomous workers that plan multi-step changes, run tests and ship code with human approval gates."],"sources":[("OpenAI","https://openai.com/news/product-releases/"),("Releasebot","https://releasebot.io/updates/openai")]},
    {"sub":"Agents & Automation","h3":"ServiceNow rolls out Autonomous Workforce across business functions","summary":"ServiceNow began launching role-scoped AI specialists in June and pitched itself as the governance layer for enterprise agents.","body":["ServiceNow extended its Autonomous Workforce with IT AI specialists launching in June and security and risk specialists in preview, positioning its workflow platform as the substrate agents need to act on enterprise data and systems. The company says its agents resolve 91 percent of cases without reassignment.","ServiceNow is selling an AI Control Tower to govern agents regardless of where they are built, competing with Salesforce Agentforce as enterprises increasingly run agents across multiple platforms."],"sources":[("ServiceNow Newsroom","https://newsroom.servicenow.com/press-releases/details/2026/ServiceNow-brings-Autonomous-Workforce-to-every-major-business-function/default.aspx"),("CX Today","https://www.cxtoday.com/security-privacy-compliance/servicenow-ai-agent-governance-knowledge-2026/")]},
    {"sub":"Agents & Automation","h3":"Gartner projects AI agent software spending to hit $206B in 2026","summary":"Agentic AI has become a shared strategic direction across clouds and enterprise software, with spending forecast to jump 139 percent.","body":["Gartner forecasts AI agent software spending will reach about 206.5 billion dollars in 2026, up 139 percent from 86.4 billion in 2025, as AWS, Google Cloud, IBM, Microsoft, GitHub, Databricks and BCG all frame agents as a new software layer. Real-time data processing has shifted from niche to core for automated decision-making.","IBM used its Think 2026 event to argue that leaders are not deploying more AI but redesigning operations, launching watsonx Orchestrate for multi-agent orchestration and governance tooling to manage agents like critical infrastructure."],"sources":[("Kanishk Agrawal","https://kanishkagrawal.com/agentic-ai-ai-agents-enterprise-automation-2026/"),("IBM Newsroom","https://newsroom.ibm.com/2026-05-05-think-2026-ibm-delivers-the-blueprint-for-the-ai-operating-model-as-the-ai-divide-widens")]},
    {"sub":"Enterprise & Regulation","h3":"EU Parliament delays high-risk AI Act rules in Digital Omnibus vote","summary":"On June 16 lawmakers approved amendments pushing back high-risk obligations while transparency rules still take effect in August.","body":["The EU Parliament passed amendments delaying key high-risk provisions of the AI Act, with standalone high-risk systems in Annex III now taking effect from December 2027 rather than August 2026, a 16-month slip approved as part of the Digital Omnibus. Watermarking obligations also shifted to December 2026.","Article 50 transparency obligations still apply from August 2, 2026, requiring providers and deployers to disclose certain AI functionalities. The changes give companies more runway while regulators recalibrate the landmark framework."],"sources":[("Sidley Data Matters","https://datamatters.sidley.com/2026/06/24/eu-ai-act-transparency-obligations-preparing-for-compliance-by-2-august-2026/"),("Morgan Lewis","https://www.morganlewis.com/pubs/2026/06/eu-approves-delays-and-other-amendments-to-certain-eu-ai-act-obligations-what-businesses-should-know")]},
    {"sub":"Enterprise & Regulation","h3":"Anthropic suspends top Claude models worldwide on Commerce directive","summary":"A June 12 export-control order forced Anthropic to cut off foreign access to Fable 5 and Mythos 5, taking both offline for everyone.","body":["The Commerce Department directive ordered Anthropic to bar any foreign national worldwide from its most advanced models, citing national security. Because nationality cannot be verified per request in real time, the practical effect was a full shutdown of Fable 5 and Mythos 5.","The order followed Anthropic's own lobbying for tighter export controls after the alleged Alibaba distillation campaign, illustrating how security policy is now directly shaping who can use frontier models, with US access expected to resume around July 1."],"sources":[("Cryptobriefing","https://cryptobriefing.com/anthropic-congress-ai-export-controls-alibaba/"),("Releasebot","https://releasebot.io/updates/anthropic/claude")]},
    {"sub":"Enterprise & Regulation","h3":"Trump signs executive order on advanced AI innovation and security","summary":"A June 2 executive order set priorities for promoting advanced AI while tightening security, carrying forward the administration's cyber strategy.","body":["President Trump issued the executive order Promoting Advanced Artificial Intelligence Innovation and Security on June 2, advancing themes from his March 2026 cyber strategy. The order frames AI leadership as both an economic and national security priority.","The policy direction underpins recent government moves to gate frontier model releases, including the request that OpenAI limit its GPT-5.6 rollout to trusted partners, signaling deeper coordination between Washington and US labs."],"sources":[("CNN Business","https://www.cnn.com/2026/06/25/tech/openai-limit-release-white-house"),("Holland & Knight","https://www.hklaw.com/en/insights/publications/2026/04/us-companies-face-eu-ai-acts-possible-august-2026-compliance-deadline")]},
]
